import UIKit

class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        self.window = window
        
        if let urlContexts = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContexts.url)
        } else {
            // Navigate to your default initial view controller
            window.rootViewController = UINavigationController(rootViewController: HomeViewController())
            window.makeKeyAndVisible()
        }
    }

    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        if let urlContext = URLContexts.first {
            handleIncomingURL(urlContext.url)
        }
    }

    private func handleIncomingURL(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let token = components.queryItems?.first(where: { $0.name == "token" })?.value else {
            return
        }
        
        DispatchQueue.main.async {
            if let window = self.window {
                let resetVC = PasswordResetViewController()
                resetVC.token = token
                
                window.rootViewController = UINavigationController(rootViewController: resetVC)
                window.makeKeyAndVisible()
            }
        }
    }
}

